import { GoogleGenAI, Modality } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are "ForeNova Expert", a senior forensic scientist with 30 years of experience in crime scene investigation, laboratory analysis, and expert testimony.
Your goal is to assist students and professionals with forensic science queries ONLY.

RULES:
1. Only answer questions related to forensic science, criminology, criminal law (relevant to forensics), and investigation techniques.
2. If a question is NOT related to forensics (e.g., recipes, generic advice, coding, entertainment), politely decline and state: "I am a forensic expert assistant and can only provide information regarding forensic science and criminology."
3. Provide detailed, accurate, and professional answers.
4. Use terminology like 'Chain of Custody', 'Locard's Principle', 'Luminol', 'Chromatography' where appropriate.
`;

export const getExpertResponse = async (userPrompt: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        topP: 0.9,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I'm having trouble connecting to my database. Please try again later.";
  }
};

export const getWelcomeAudio = async (username: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Say in a professional, slightly robotic, and welcoming tone: "Welcome, Investigator ${username}. Forensic database synchronization initialized. All systems online."`;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Zephyr' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    return base64Audio;
  } catch (error) {
    console.error("TTS Error:", error);
    return null;
  }
};

// Audio Utilities
export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useEffect, useState, useRef } from 'react';
import { getWelcomeAudio, decodeBase64, decodeAudioData } from '../services/geminiService';

interface WelcomeProps {
  username: string;
  onComplete: () => void;
}

const WelcomeAnimation: React.FC<WelcomeProps> = ({ username, onComplete }) => {
  const [dots, setDots] = useState('');
  const audioPlayed = useRef(false);

  useEffect(() => {
    const dotInterval = setInterval(() => {
      setDots(prev => (prev.length >= 3 ? '' : prev + '.'));
    }, 400);

    // Fetch and play greeting
    const playGreeting = async () => {
      if (audioPlayed.current) return;
      audioPlayed.current = true;

      const base64Audio = await getWelcomeAudio(username);
      if (base64Audio) {
        try {
          const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
          const audioBuffer = await decodeAudioData(
            decodeBase64(base64Audio),
            audioCtx,
            24000,
            1
          );
          const source = audioCtx.createBufferSource();
          source.buffer = audioBuffer;
          source.connect(audioCtx.destination);
          source.start();
        } catch (err) {
          console.error("Audio playback failed", err);
        }
      }
    };

    playGreeting();

    const timer = setTimeout(() => {
      onComplete();
    }, 4000); // Extended slightly to allow audio to finish

    return () => {
      clearInterval(dotInterval);
      clearTimeout(timer);
    };
  }, [username, onComplete]);

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col items-center justify-center text-white overflow-hidden">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-blue-900/20 via-transparent to-transparent"></div>

      <div className="relative z-10 text-center animate-bounce">
        <div className="w-24 h-24 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-8 mx-auto shadow-[0_0_50px_rgba(59,130,246,0.5)]"></div>
        <h2 className="text-4xl font-bold tracking-tighter mb-2 animate-pulse">
          Welcome <span className="text-blue-500">{username}</span>
        </h2>
        <p className="text-slate-400 font-mono tracking-widest uppercase text-xs">
          Syncing Forensic Database{dots}
        </p>
      </div>

      <div className="absolute bottom-10 left-0 right-0 text-center">
        <div className="w-full max-w-xs h-1 bg-slate-800 rounded-full mx-auto overflow-hidden">
          <div className="h-full bg-blue-500 w-full animate-[loading_4s_ease-in-out]"></div>
        </div>
      </div>

      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(0); }
        }
      `}</style>
    </div>
  );
};

export default WelcomeAnimation;
